public class ListNode {
    int val;
    ListNode next;
    ListNode() {}
    ListNode(int val) { this.val = val; }
    ListNode(int val, ListNode next) { this.val = val; this.next = next; }
}

public ListNode reverseKGroup(ListNode head, int k) {
    if (head == null || k == 1) return head;

    int len = 0;
    ListNode cur = head;
    while (cur != null) {
        len++;
        cur = cur.next;
    }

    ListNode dummy = new ListNode(0);
    dummy.next = head;
    ListNode prev = dummy;
    cur = head;

    while (len >= k) {
        for (int i = 1; i < k; i++) {
            ListNode temp = cur.next;
            cur.next = temp.next;
            temp.next = prev.next;
            prev.next = temp;
        }
        prev = cur;
        cur = cur.next;
        len -= k;
    }

    return dummy.next;
}
```


